import{_ as a,o as i,c as n,ai as s}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Workspace Memory Research","description":"","frontmatter":{"summary":"Research notes: offline memory system for Clawd workspaces (Markdown source-of-truth + derived index)","read_when":["Designing workspace memory (~/.opensoul/workspace) beyond daily Markdown logs",{"Deciding":"standalone CLI vs deep OpenSoul integration"},"Adding offline recall + reflection (retain/recall/reflect)"],"title":"Workspace Memory Research"},"headers":[],"relativePath":"experiments/research/memory.md","filePath":"experiments/research/memory.md","lastUpdated":1771906665000}'),l={name:"experiments/research/memory.md"};function t(o,e,r,c,d,p){return i(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="workspace-memory-v2-offline-research-notes" tabindex="-1"><a class="header-anchor" href="#workspace-memory-v2-offline-research-notes">#</a> Workspace Memory v2 (offline): research notes</h1><p>Target: Clawd-style workspace (<code>agents.defaults.workspace</code>, default <code>~/.opensoul/workspace</code>) where “memory” is stored as one Markdown file per day (<code>memory/YYYY-MM-DD.md</code>) plus a small set of stable files (e.g. <code>memory.md</code>, <code>SOUL.md</code>).</p><p>This doc proposes an <strong>offline-first</strong> memory architecture that keeps Markdown as the canonical, reviewable source of truth, but adds <strong>structured recall</strong> (search, entity summaries, confidence updates) via a derived index.</p><h2 id="why-change" tabindex="-1"><a class="header-anchor" href="#why-change">#</a> Why change?</h2><p>The current setup (one file per day) is excellent for:</p><ul><li>“append-only” journaling</li><li>human editing</li><li>git-backed durability + auditability</li><li>low-friction capture (“just write it down”)</li></ul><p>It’s weak for:</p><ul><li>high-recall retrieval (“what did we decide about X?”, “last time we tried Y?”)</li><li>entity-centric answers (“tell me about Alice / The Castle / warelay”) without rereading many files</li><li>opinion/preference stability (and evidence when it changes)</li><li>time constraints (“what was true during Nov 2025?”) and conflict resolution</li></ul><h2 id="design-goals" tabindex="-1"><a class="header-anchor" href="#design-goals">#</a> Design goals</h2><ul><li><strong>Offline</strong>: works without network; can run on laptop/Castle; no cloud dependency.</li><li><strong>Explainable</strong>: retrieved items should be attributable (file + location) and separable from inference.</li><li><strong>Low ceremony</strong>: daily logging stays Markdown, no heavy schema work.</li><li><strong>Incremental</strong>: v1 is useful with FTS only; semantic/vector and graphs are optional upgrades.</li><li><strong>Agent-friendly</strong>: makes “recall within token budgets” easy (return small bundles of facts).</li></ul><h2 id="north-star-model-hindsight-×-letta" tabindex="-1"><a class="header-anchor" href="#north-star-model-hindsight-×-letta">#</a> North star model (Hindsight × Letta)</h2><p>Two pieces to blend:</p><ol><li><strong>Letta/MemGPT-style control loop</strong></li></ol><ul><li>keep a small “core” always in context (persona + key user facts)</li><li>everything else is out-of-context and retrieved via tools</li><li>memory writes are explicit tool calls (append/replace/insert), persisted, then re-injected next turn</li></ul><ol start="2"><li><strong>Hindsight-style memory substrate</strong></li></ol><ul><li>separate what’s observed vs what’s believed vs what’s summarized</li><li>support retain/recall/reflect</li><li>confidence-bearing opinions that can evolve with evidence</li><li>entity-aware retrieval + temporal queries (even without full knowledge graphs)</li></ul><h2 id="proposed-architecture-markdown-source-of-truth-derived-index" tabindex="-1"><a class="header-anchor" href="#proposed-architecture-markdown-source-of-truth-derived-index">#</a> Proposed architecture (Markdown source-of-truth + derived index)</h2><h3 id="canonical-store-git-friendly" tabindex="-1"><a class="header-anchor" href="#canonical-store-git-friendly">#</a> Canonical store (git-friendly)</h3><p>Keep <code>~/.opensoul/workspace</code> as canonical human-readable memory.</p><p>Suggested workspace layout:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.opensoul/workspace/</span></span>
<span class="line"><span>  memory.md                    # small: durable facts + preferences (core-ish)</span></span>
<span class="line"><span>  memory/</span></span>
<span class="line"><span>    YYYY-MM-DD.md              # daily log (append; narrative)</span></span>
<span class="line"><span>  bank/                        # “typed” memory pages (stable, reviewable)</span></span>
<span class="line"><span>    world.md                   # objective facts about the world</span></span>
<span class="line"><span>    experience.md              # what the agent did (first-person)</span></span>
<span class="line"><span>    opinions.md                # subjective prefs/judgments + confidence + evidence pointers</span></span>
<span class="line"><span>    entities/</span></span>
<span class="line"><span>      Peter.md</span></span>
<span class="line"><span>      The-Castle.md</span></span>
<span class="line"><span>      warelay.md</span></span>
<span class="line"><span>      ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>Notes:</p><ul><li><strong>Daily log stays daily log</strong>. No need to turn it into JSON.</li><li>The <code>bank/</code> files are <strong>curated</strong>, produced by reflection jobs, and can still be edited by hand.</li><li><code>memory.md</code> remains “small + core-ish”: the things you want Clawd to see every session.</li></ul><h3 id="derived-store-machine-recall" tabindex="-1"><a class="header-anchor" href="#derived-store-machine-recall">#</a> Derived store (machine recall)</h3><p>Add a derived index under the workspace (not necessarily git tracked):</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.opensoul/workspace/.memory/index.sqlite</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Back it with:</p><ul><li>SQLite schema for facts + entity links + opinion metadata</li><li>SQLite <strong>FTS5</strong> for lexical recall (fast, tiny, offline)</li><li>optional embeddings table for semantic recall (still offline)</li></ul><p>The index is always <strong>rebuildable from Markdown</strong>.</p><h2 id="retain-recall-reflect-operational-loop" tabindex="-1"><a class="header-anchor" href="#retain-recall-reflect-operational-loop">#</a> Retain / Recall / Reflect (operational loop)</h2><h3 id="retain-normalize-daily-logs-into-facts" tabindex="-1"><a class="header-anchor" href="#retain-normalize-daily-logs-into-facts">#</a> Retain: normalize daily logs into “facts”</h3><p>Hindsight’s key insight that matters here: store <strong>narrative, self-contained facts</strong>, not tiny snippets.</p><p>Practical rule for <code>memory/YYYY-MM-DD.md</code>:</p><ul><li>at end of day (or during), add a <code>## Retain</code> section with 2–5 bullets that are: <ul><li>narrative (cross-turn context preserved)</li><li>self-contained (standalone makes sense later)</li><li>tagged with type + entity mentions</li></ul></li></ul><p>Example:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Retain</span></span>
<span class="line"><span>- W @Peter: Currently in Marrakech (Nov 27–Dec 1, 2025) for Andy’s birthday.</span></span>
<span class="line"><span>- B @warelay: I fixed the Baileys WS crash by wrapping connection.update handlers in try/catch (see memory/2025-11-27.md).</span></span>
<span class="line"><span>- O(c=0.95) @Peter: Prefers concise replies (&amp;lt;1500 chars) on WhatsApp; long content goes into files.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Minimal parsing:</p><ul><li>Type prefix: <code>W</code> (world), <code>B</code> (experience/biographical), <code>O</code> (opinion), <code>S</code> (observation/summary; usually generated)</li><li>Entities: <code>@Peter</code>, <code>@warelay</code>, etc (slugs map to <code>bank/entities/*.md</code>)</li><li>Opinion confidence: <code>O(c=0.0..1.0)</code> optional</li></ul><p>If you don’t want authors to think about it: the reflect job can infer these bullets from the rest of the log, but having an explicit <code>## Retain</code> section is the easiest “quality lever”.</p><h3 id="recall-queries-over-the-derived-index" tabindex="-1"><a class="header-anchor" href="#recall-queries-over-the-derived-index">#</a> Recall: queries over the derived index</h3><p>Recall should support:</p><ul><li><strong>lexical</strong>: “find exact terms / names / commands” (FTS5)</li><li><strong>entity</strong>: “tell me about X” (entity pages + entity-linked facts)</li><li><strong>temporal</strong>: “what happened around Nov 27” / “since last week”</li><li><strong>opinion</strong>: “what does Peter prefer?” (with confidence + evidence)</li></ul><p>Return format should be agent-friendly and cite sources:</p><ul><li><code>kind</code> (<code>world|experience|opinion|observation</code>)</li><li><code>timestamp</code> (source day, or extracted time range if present)</li><li><code>entities</code> (<code>[&quot;Peter&quot;,&quot;warelay&quot;]</code>)</li><li><code>content</code> (the narrative fact)</li><li><code>source</code> (<code>memory/2025-11-27.md#L12</code> etc)</li></ul><h3 id="reflect-produce-stable-pages-update-beliefs" tabindex="-1"><a class="header-anchor" href="#reflect-produce-stable-pages-update-beliefs">#</a> Reflect: produce stable pages + update beliefs</h3><p>Reflection is a scheduled job (daily or heartbeat <code>ultrathink</code>) that:</p><ul><li>updates <code>bank/entities/*.md</code> from recent facts (entity summaries)</li><li>updates <code>bank/opinions.md</code> confidence based on reinforcement/contradiction</li><li>optionally proposes edits to <code>memory.md</code> (“core-ish” durable facts)</li></ul><p>Opinion evolution (simple, explainable):</p><ul><li>each opinion has: <ul><li>statement</li><li>confidence <code>c ∈ [0,1]</code></li><li>last_updated</li><li>evidence links (supporting + contradicting fact IDs)</li></ul></li><li>when new facts arrive: <ul><li>find candidate opinions by entity overlap + similarity (FTS first, embeddings later)</li><li>update confidence by small deltas; big jumps require strong contradiction + repeated evidence</li></ul></li></ul><h2 id="cli-integration-standalone-vs-deep-integration" tabindex="-1"><a class="header-anchor" href="#cli-integration-standalone-vs-deep-integration">#</a> CLI integration: standalone vs deep integration</h2><p>Recommendation: <strong>deep integration in OpenSoul</strong>, but keep a separable core library.</p><h3 id="why-integrate-into-opensoul" tabindex="-1"><a class="header-anchor" href="#why-integrate-into-opensoul">#</a> Why integrate into OpenSoul?</h3><ul><li>OpenSoul already knows: <ul><li>the workspace path (<code>agents.defaults.workspace</code>)</li><li>the session model + heartbeats</li><li>logging + troubleshooting patterns</li></ul></li><li>You want the agent itself to call the tools: <ul><li><code>opensoul memory recall &quot;…&quot; --k 25 --since 30d</code></li><li><code>opensoul memory reflect --since 7d</code></li></ul></li></ul><h3 id="why-still-split-a-library" tabindex="-1"><a class="header-anchor" href="#why-still-split-a-library">#</a> Why still split a library?</h3><ul><li>keep memory logic testable without gateway/runtime</li><li>reuse from other contexts (local scripts, future desktop app, etc.)</li></ul><p>Shape: The memory tooling is intended to be a small CLI + library layer, but this is exploratory only.</p><h2 id="s-collide-suco-when-to-use-it-research" tabindex="-1"><a class="header-anchor" href="#s-collide-suco-when-to-use-it-research">#</a> “S-Collide” / SuCo: when to use it (research)</h2><p>If “S-Collide” refers to <strong>SuCo (Subspace Collision)</strong>: it’s an ANN retrieval approach that targets strong recall/latency tradeoffs by using learned/structured collisions in subspaces (paper: arXiv 2411.14754, 2024).</p><p>Pragmatic take for <code>~/.opensoul/workspace</code>:</p><ul><li><strong>don’t start</strong> with SuCo.</li><li>start with SQLite FTS + (optional) simple embeddings; you’ll get most UX wins immediately.</li><li>consider SuCo/HNSW/ScaNN-class solutions only once: <ul><li>corpus is big (tens/hundreds of thousands of chunks)</li><li>brute-force embedding search becomes too slow</li><li>recall quality is meaningfully bottlenecked by lexical search</li></ul></li></ul><p>Offline-friendly alternatives (in increasing complexity):</p><ul><li>SQLite FTS5 + metadata filters (zero ML)</li><li>Embeddings + brute force (works surprisingly far if chunk count is low)</li><li>HNSW index (common, robust; needs a library binding)</li><li>SuCo (research-grade; attractive if there’s a solid implementation you can embed)</li></ul><p>Open question:</p><ul><li>what’s the <strong>best</strong> offline embedding model for “personal assistant memory” on your machines (laptop + desktop)? <ul><li>if you already have Ollama: embed with a local model; otherwise ship a small embedding model in the toolchain.</li></ul></li></ul><h2 id="smallest-useful-pilot" tabindex="-1"><a class="header-anchor" href="#smallest-useful-pilot">#</a> Smallest useful pilot</h2><p>If you want a minimal, still-useful version:</p><ul><li>Add <code>bank/</code> entity pages and a <code>## Retain</code> section in daily logs.</li><li>Use SQLite FTS for recall with citations (path + line numbers).</li><li>Add embeddings only if recall quality or scale demands it.</li></ul><h2 id="references" tabindex="-1"><a class="header-anchor" href="#references">#</a> References</h2><ul><li>Letta / MemGPT concepts: “core memory blocks” + “archival memory” + tool-driven self-editing memory.</li><li>Hindsight Technical Report: “retain / recall / reflect”, four-network memory, narrative fact extraction, opinion confidence evolution.</li><li>SuCo: arXiv 2411.14754 (2024): “Subspace Collision” approximate nearest neighbor retrieval.</li></ul>`,69)])])}const m=a(l,[["render",t]]);export{h as __pageData,m as default};
